#include <vector>
#include <algorithm>

using namespace std;

typedef long long ll;

ll MOD = 1e9 + 7;
const int MAXN = 100005;

ll factorial[MAXN];
ll invFactorial[MAXN];

// Modular exponentiation: (base^exp) % mod
ll power(ll base, ll exp) {
    ll res = 1;
    base %= MOD;
    while (exp > 0) {
        if (exp % 2 == 1) res = (res * base) % MOD;
        base = (base * base) % MOD;
        exp /= 2;
    }
    return res;
}

// Modular inverse using Fermat's Little Theorem: a^(MOD-2) % MOD
ll modInverse(ll n) {
    return power(n, MOD - 2);
}

// Precompute factorials and inverse factorials
void precompute_factorials(int max_val) {
    factorial[0] = 1;
    for (int i = 1; i <= max_val; i++) {
        factorial[i] = (factorial[i - 1] * i) % MOD;
    }
    invFactorial[max_val] = modInverse(factorial[max_val]);
    for (int i = max_val - 1; i >= 0; i--) {
        invFactorial[i] = (invFactorial[i + 1] * (i + 1)) % MOD;
    }
}

// Binomial coefficient C(n, r) % MOD
ll nCr(int n, int r) {
    if (r < 0 || r > n) return 0;
    if (r == 0 || r == n) return 1;
    if (r > n / 2) r = n - r;

    // C(n, r) = n! / (r! * (n-r)!)
    ll num = factorial[n];
    ll den = (invFactorial[r] * invFactorial[n - r]) % MOD;
    return (num * den) % MOD;
}


long long solve(long long n_ll, long long pos_ll, long long k_ll) {
    // Since N <= 10^5, we can safely cast inputs for array indexing/loops if they fit standard integer types.
    int n = (int)n_ll;
    int pos = (int)pos_ll;
    int k = (int)k_ll;

    // Precompute factorials up to N
    // This setup assumes solve might be called multiple times in a contest environment, 
    // but for a single run, we must ensure it runs correctly.
    static bool initialized = false;
    if (!initialized) {
        precompute_factorials(MAXN - 1);
        initialized = true;
    }

    // Number of people to the left (N_L)
    int N_L = pos;
    // Number of people to the right (N_R)
    int N_R = n - 1 - pos;

    ll W_others = 0;

    // We need L_count + R_count = K. L_count is 'l'. R_count is 'k - l'.

    // l must be <= N_L and >= 0
    // k - l must be <= N_R and >= 0 => l >= k - N_R

    int l_min = max(0, k - N_R);
    int l_max = min(k, N_L);

    for (int l = l_min; l <= l_max; ++l) {
        int r = k - l;

        // Ways to choose l people on the left to say 'L': C(N_L, l)
        ll ways_L = nCr(N_L, l);

        // Ways to choose r people on the right to say 'R': C(N_R, r)
        ll ways_R = nCr(N_R, r);

        ll current_ways = (ways_L * ways_R) % MOD;
        W_others = (W_others + current_ways) % MOD;
    }

    // The person at 'pos' has 2 choices ('L' or 'R'), which doubles the total count.
    ll total_ways = (2 * W_others) % MOD;

    // Special check: If N=0 (not possible by constraints, but good practice), W_others might be 0.
    // Since N >= 1, W_others is at least 1 if K is achievable (e.g., N=1, K=0 -> W_others=1).

    return total_ways;
}

